	app.parseAndTranslate('partials/notifications_list', { notifications }, function (html) {
		notifList.html(html);

		// Update dropdown position after async content load
		const dropdownToggle = notifList.closest('.dropdown').find('[data-bs-toggle="dropdown"]').get(0);
		if (dropdownToggle) {
			const bsDropdown = bootstrap.Dropdown.getInstance(dropdownToggle);
			if (bsDropdown) {
				bsDropdown.update();
			}
		}

		notifList.off('click').on('click', '[data-nid]', function (ev) {
			const notifEl = $(this);
			if (scrollToPostIndexIfOnPage(notifEl)) {
				ev.stopPropagation();
				ev.preventDefault();
				components.get('notifications/list').dropdown('toggle');
