			const unread = notifEl.hasClass('unread');
			if (!unread) {
				return;
			}
			const nid = notifEl.attr('data-nid');
			markNotification(nid, true);
		});
		components.get('notifications').on('click', '.mark-all-read', Notifications.markAllRead);

