categorySelector.modal = function (options) {
	options = options || {};
	options.onSelect = options.onSelect || function () {};
	options.onSubmit = options.onSubmit || function () {};
	app.parseAndTranslate('admin/partials/categories/select-category', { message: options.message }, function (html) {
		const modal = bootbox.dialog({
			title: options.title || '[[modules:composer.select-category]]',
			message: html,
			buttons: {
				save: {
					label: '[[global:select]]',
					className: 'btn-primary',
					callback: submit,
				},
			},
		});

		const selectorEl = modal.find('[component="category-selector"]');

		// Add dropup class to handle dropdown positioning in modal context
		selectorEl.on('show.bs.dropdown', function () {
			const $toggle = $(this).find('[data-bs-toggle="dropdown"]');
			if ($toggle.length) {
				const toggleTop = $toggle.offset().top;
				const modalBottom = modal.find('.modal-content').offset().top + modal.find('.modal-content').outerHeight();
				// Add dropup class if dropdown would overflow the modal
				$(this).toggleClass('dropup', toggleTop > (modalBottom - 200));
			}
		});

		const selector = categorySelector.init(selectorEl, options);
		function submit(ev) {
			ev.preventDefault();
			if (selector.selectedCategory) {
				options.onSubmit(selector.selectedCategory);
				modal.modal('hide');
			}
			return false;
		}
		if (options.openOnLoad) {

